        "model": "minimax-portal/MiniMax-M2.1"
      },
      "delivery": {
        "mode": "announce",
        "channel": "feishu",
        "to": "oc_0a896a034969bc14f9fca0412a8701b4,oc_7873da17e98fa210dff4161ca6defd46"
      },
      "state": {
        "nextRunAtMs": 1770593400000,
        "lastRunAtMs": 1770563804234,
        "lastStatus": "ok",
        "lastDurationMs": 100973,
        "runningAtMs": 1770593400010
